/* ── primitives ────────────────────────────────────────────────────────── */
const Card = ({ children, style={}, onClick }) => {
  const [h,setH] = useState(false);
  return <div onClick={onClick}
    onMouseEnter={()=>onClick&&setH(true)} onMouseLeave={()=>setH(false)}
    style={{ background:C.card, borderRadius:14, padding:20, border:`1px solid ${C.border}`,
      boxShadow:h?"0 8px 28px rgba(6,131,135,0.16)":"0 2px 8px rgba(6,131,135,0.06)",
      transform:h?"translateY(-2px)":"none", transition:"all 0.2s",
      cursor:onClick?"pointer":"default", ...style }}>{children}</div>;
};

const Tag = ({ label, color=C.primary, Icon:I }) => (
  <span style={{ background:color+"22", color, borderRadius:20, padding:"3px 11px",
    fontSize:11, fontWeight:700, marginRight:6, display:"inline-flex", alignItems:"center", gap:4,
    fontFamily:"'Encode Sans Condensed',sans-serif", letterSpacing:0.4 }}>
    {I&&<I size={10}/>}{label}
  </span>
);

const Btn = ({ label, onClick, color=C.primary, outline=false, small=false, Icon:I, full=false, disabled=false }) => {
  const [h,setH] = useState(false);
  return <button onClick={disabled?undefined:onClick}
    onMouseEnter={()=>!disabled&&setH(true)} onMouseLeave={()=>setH(false)}
    style={{ background:disabled?"#ddd":outline?(h?color+"14":"transparent"):(h?"#056a6e":color),
      color:disabled?"#999":outline?color:C.white,
      border:`2px solid ${disabled?"#ddd":outline?color:"transparent"}`,
      borderRadius:9, padding:small?"6px 14px":"10px 22px", fontSize:small?12:13,
      fontWeight:700, cursor:disabled?"not-allowed":"pointer", transition:"all 0.18s",
      fontFamily:"'Jost',sans-serif", display:"inline-flex", alignItems:"center", gap:6,
      width:full?"100%":"auto", justifyContent:full?"center":"flex-start" }}>
    {I&&<I size={small?12:14}/>}{label}
  </button>;
};

const ProgressBar = ({ value, color=C.primary, label, sub, max=100 }) => {
  const pct = max===100?value:Math.round((value/max)*100);
  return <div style={{ marginBottom:14 }}>
    <div style={{ display:"flex", justifyContent:"space-between", marginBottom:5 }}>
      <span style={{ fontSize:13, color:C.text, fontWeight:600 }}>{label}</span>
      <span style={{ fontSize:13, color, fontWeight:800 }}>{max===100?`${value}%`:`${value}/${max}`}</span>
    </div>
    {sub&&<div style={{ fontSize:11, color:C.textLight, marginBottom:4 }}>{sub}</div>}
    <div style={{ background:C.border, borderRadius:10, height:9, overflow:"hidden" }}>
      <div style={{ width:`${pct}%`, background:`linear-gradient(90deg,${color},${color}bb)`, height:"100%", borderRadius:10 }}/>
    </div>
  </div>;
};

