/* ══ LOGIN MODAL ═══════════════════════════════════════════════════════════ */
const LoginModal = ({ onLogin, onClose }) => {
  const [email,setEmail] = useState(""); const [pass,setPass] = useState("");
  const [err,setErr] = useState(""); const [tab,setTab] = useState("login");
  const doLogin = () => {
    const u = MOCK_USERS[email.toLowerCase()];
    if(u&&u.password===pass) onLogin(u.role,u.name);
    else setErr("Invalid credentials. Demo: user@magno.eu / user123  or  admin@magno.eu / admin123");
  };
  const inp = { width:"100%", padding:"11px 14px", borderRadius:9, border:`1px solid ${C.border}`,
    fontSize:13, boxSizing:"border-box", outline:"none", color:C.text,
    fontFamily:"'Jost',sans-serif", marginBottom:12 };
  return (
    <div style={{ position:"fixed", inset:0, background:"rgba(11,65,73,0.55)", zIndex:1000,
      display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
      <div style={{ background:C.white, borderRadius:18, padding:"36px 32px", width:"100%",
        maxWidth:420, boxShadow:"0 20px 60px rgba(11,65,73,0.3)", position:"relative" }}>
        <button onClick={onClose} style={{ position:"absolute", top:16, right:16, background:"none",
          border:"none", cursor:"pointer", color:C.textLight }}><X size={20}/></button>
        <div style={{ textAlign:"center", marginBottom:24 }}>
          <img src={LOGO_B64} alt="MAGNO" style={{ height:44, width:"auto", marginBottom:12 }}/>
          <h3 style={{ margin:0, fontSize:20, fontWeight:900, color:C.dark, fontFamily:"'Jost',sans-serif" }}>
            {tab==="login"?"Welcome back":"Join MAGNO"}
          </h3>
          
        </div>
        <div style={{ display:"flex", gap:8, marginBottom:22 }}>
          {[["login","Log In"],["register","Register"]].map(([id,l])=>(
            <button key={id} onClick={()=>setTab(id)} style={{ flex:1, padding:"9px", borderRadius:9,
              fontWeight:700, fontSize:13, border:`2px solid ${tab===id?C.primary:C.border}`,
              background:tab===id?C.primary:C.card, color:tab===id?C.white:C.textMid,
              cursor:"pointer", fontFamily:"'Jost',sans-serif" }}>{l}</button>
          ))}
        </div>
        {tab==="login" ? <>
          <input value={email} onChange={e=>setEmail(e.target.value)} placeholder="Email address" type="email" style={inp}/>
          <input value={pass} onChange={e=>setPass(e.target.value)} placeholder="Password" type="password"
            style={{...inp,marginBottom:8}} onKeyDown={e=>e.key==="Enter"&&doLogin()}/>
          {err&&<div style={{ fontSize:12, color:C.red, marginBottom:12, lineHeight:1.5 }}>{err}</div>}
          <div style={{ fontSize:11, color:C.textLight, marginBottom:16 }}>
            Demo — user: <b>user@magno.eu / user123</b><br/>Admin: <b>admin@magno.eu / admin123</b>
          </div>
          <Btn label="Log In" color={C.primary} Icon={LogIn} onClick={doLogin} full/>
        </> : <>
          <input placeholder="Full name" style={inp}/>
          <input placeholder="Email address" type="email" style={inp}/>
          <input placeholder="Organisation (optional)" style={inp}/>
          <input placeholder="Password" type="password" style={{...inp,marginBottom:8}}/>
          <div style={{ fontSize:11, color:C.textLight, marginBottom:16 }}>
            By registering you agree to the MAGNO platform terms and privacy policy.
          </div>
          <Btn label="Create Free Account" color={C.lime} Icon={UserPlus} full onClick={()=>onLogin("user","New User")}/>
        </>}
      </div>
    </div>
  );
};

